// Extract error details and booking context for rollback
const errorData = $input.first().json;

// Get workflow context
const workflowId = errorData.workflow?.id || 'UNKNOWN';
const workflowName = errorData.workflow?.name || 'UNKNOWN';
const executionId = errorData.execution?.id || 'MANUAL';
const lastNode = errorData.execution?.lastNodeExecuted || '';
const errorMessage = errorData.execution?.error?.message || 'Unknown error';

// Try to extract booking context from input data
const inputData = errorData.execution?.data?.result_data || {};
const bookingContext = {
  provider_id: inputData.provider_id || null,
  service_id: inputData.service_id || null,
  start_time: inputData.start_time || null,
  customer_id: inputData.customer_id || inputData.chat_id || null,
  idempotency_key: inputData.idempotency_key || null
};

// Determine what needs to be rolled back based on which node failed
let rollbackData = {
  booking_id: null,
  gcal_event_id: null,
  lock_id: null,
  lock_key: null,
  reason: `auto_rollback_from_${lastNode}`
};

// If failed after GCal creation, we need to rollback GCal
if (lastNode.includes('GCal') || lastNode.includes('Calendar')) {
  rollbackData.gcal_event_id = inputData.gcal_event_id || inputData.eventId || null;
}

// If failed after DB insert, we need to rollback DB
if (lastNode.includes('DB') || lastNode.includes('Postgres')) {
  rollbackData.booking_id = inputData.booking_id || null;
}

// If failed after lock acquisition, we need to release lock
if (lastNode.includes('Lock')) {
  rollbackData.lock_id = inputData.lock_id || null;
  rollbackData.lock_key = inputData.lock_key || null;
}

return [{
  json: {
    workflow_id: workflowId,
    workflow_name: workflowName,
    execution_id: executionId,
    error_message: errorMessage,
    last_node: lastNode,
    booking_context: bookingContext,
    rollback_data: rollbackData,
    timestamp: new Date().toISOString()
  }
}];

// Build rollback payload for WF6
const input = $input.first().json;
const rollback = input.rollback_data;
const context = input.booking_context;

// Use context to fill in missing rollback data
if (!rollback.booking_id && context.idempotency_key) {
  // We don't have booking_id yet, but we can try to find it
  rollback.booking_id = null; // Will be looked up by WF6 if needed
}

// Build lock_key from context if not available
if (!rollback.lock_key && context.provider_id && context.start_time) {
  const safeTime = String(context.start_time).replace(/[^a-zA-Z0-9T:.+\-]/g, '_');
  rollback.lock_key = `lock_${context.provider_id}_${safeTime}`;
}

// Check if we have at least one valid ID for rollback
const hasValidId = !!(rollback.booking_id || rollback.gcal_event_id || rollback.lock_id || rollback.lock_key);

return [{
  json: {
    ...rollback,
    has_valid_id: hasValidId,
    _meta: {
      source: 'WF2_ERROR_HANDLER',
      original_workflow: input.workflow_name,
      original_execution: input.execution_id,
      failed_at_node: input.last_node,
      timestamp: new Date().toISOString()
    }
  }
}];

// Log that no rollback was needed
const input = $input.first().json;
const errorContext = $('Extract Error Context').first().json;

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      error_logged: true,
      rollback_triggered: false,
      rollback_skipped_reason: 'No valid IDs to rollback (early failure)',
      original_error: errorContext.error_message,
      failed_node: errorContext.last_node,
      context: input.booking_context
    },
    _meta: {
      source: 'WF2_ERROR_HANDLER',
      timestamp: new Date().toISOString(),
      version: '1.0.1'
    }
  }
}];

// Log the error and rollback result
const input = $input.first().json;
const errorContext = $('Extract Error Context').first().json;

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      error_logged: true,
      rollback_triggered: true,
      original_error: errorContext.error_message,
      failed_node: errorContext.last_node,
      rollback_result: input
    },
    _meta: {
      source: 'WF2_ERROR_HANDLER',
      timestamp: new Date().toISOString(),
      version: '1.0.1'
    }
  }
}];
